#!/usr/bin/env node
/**
 * Regenerate modern/js/math-ai-cores.bundle.js from individual *-core.js sources.
 *
 * WHY: math-calculus-cores.inc.jsp used to load ~25 sequential scripts (LCP/INP hit).
 * Pages keep editing the source files; this script concatenates them into one request.
 *
 * Usage (from repo root):
 *   node scripts/build-math-ai-cores-bundle.mjs
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.join(__dirname, '..');
const WEBAPP = path.join(ROOT, 'src/main/webapp');
const MANIFEST = path.join(__dirname, 'math-ai-cores.manifest.json');
const OUT = path.join(WEBAPP, 'modern/js/math-ai-cores.bundle.js');

const manifest = JSON.parse(fs.readFileSync(MANIFEST, 'utf8'));
const files = manifest.files || [];
const preamble = manifest.preamble || '';

let out = `/* ========================================================================
   math-ai-cores.bundle.js — Math AI chat CAS engines (concatenated)
   Generated by scripts/build-math-ai-cores-bundle.mjs on ${new Date().toISOString()}
   DO NOT EDIT BY HAND — edit source *-core.js files, then re-run the script.

   Sources (${files.length} files — see scripts/math-ai-cores.manifest.json):
${files.map((f) => `     · ${f}`).join('\n')}
   ====================================================================== */

`;

if (preamble.trim()) {
  out += `\n/* ── preamble ── */\n${preamble.trim()}\n`;
}

let sourcesBytes = 0;
for (let i = 0; i < files.length; i++) {
  const rel = files[i];
  const abs = path.join(WEBAPP, rel);
  if (!fs.existsSync(abs)) {
    console.error(`ERROR: missing source: ${rel}`);
    process.exit(1);
  }
  const body = fs.readFileSync(abs, 'utf8');
  sourcesBytes += Buffer.byteLength(body, 'utf8');
  out += `\n\n/* === [${i + 1}/${files.length}] ${rel} === */\n`;
  out += body;
}

out += `\n\n/* ── bundle marker ── */\nwindow.__MATH_AI_CORES_LOADED__ = true;\n`;

fs.writeFileSync(OUT, out);
const bundleBytes = fs.statSync(OUT).size;
console.log(`✓ wrote ${OUT}`);
console.log(`  bundle: ${bundleBytes} bytes  (sources: ${sourcesBytes} bytes + headers)`);
